--- kern_event.c        10 Apr 2007 18:28:47 -0000      1.6 
+++ kern_event.c        13 Apr 2007 21:48:04 -0000 
@@ -937,7 +937,13 @@ findkn: 
               goto done; 
       } 

+        if (kev->flags & EV_DISABLE) { 
+            kn->kn_flags &= ~EV_ENABLE; 
+            kn->kn_flags |= EV_DISABLE; 
+        } else if (kev->flags & EV_ENABLE) { 
+            kn->kn_flags &= ~EV_DISABLE; 
+            kn->kn_flags |= EV_ENABLE; 
+        } 

       if ((kev->flags & EV_DISABLE) && 
           ((kn->kn_status & KN_DISABLED) == 0)) { 

